query:
DELETE FROM messages WHERE dialogId IN (
  SELECT d.id FROM dialogs d JOIN contacts c ON d.contactId = c.id 
  WHERE c.telegramId LIKE 'channel_%' OR c.telegramId LIKE 'group_%'
);

